from itertools import permutations

class Solution:
    def findEvenNumbers(self, digits):
        n = len(digits)
        seen = set()
        for combo in permutations(range(n), 3):
            a, b, c = combo
            if digits[a] == 0:
                continue
            if digits[c] % 2 != 0:
                continue
            seen.add(digits[a] * 100 + digits[b] * 10 + digits[c])
        return sorted(seen)

