from collections import Counter

class Solution:
    def findEvenNumbers(self, digits):
        cnt = Counter(digits)
        res = []
        for num in range(100, 1000, 2):
            need = Counter([num // 100, (num // 10) % 10, num % 10])
            if all(cnt[d] >= c for d, c in need.items()):
                res.append(num)
        return res

