var findEvenNumbers = function(digits) {
    const cnt = new Array(10).fill(0);
    for (const d of digits) cnt[d]++;
    const res = [];
    for (let num = 100; num < 1000; num += 2) {
        const need = new Array(10).fill(0);
        need[Math.floor(num / 100)]++;
        need[Math.floor(num / 10) % 10]++;
        need[num % 10]++;
        let ok = true;
        for (let d = 0; d < 10; d++) {
            if (need[d] > cnt[d]) { ok = false; break; }
        }
        if (ok) res.push(num);
    }
    return res;
};
